window.AZ_QUESTIONS = [

  /* ============================ SET 1 ============================ */

  { cat: "cloud", topic: "c_cost", q: "A manufacturing company currently maintains all its servers in an on-premises datacenter and pays for hardware, power, and cooling whether or not the servers are being used. They want to move to a model where they avoid large upfront purchases and pay only for the computing resources they actually consume. Which benefit of cloud computing does this describe?", options: ["Capital expenditure (CapEx)", "Operational expenditure (OpEx) with consumption-based pricing", "Fixed annual licensing", "Co-location hosting"], answer: 1, explain: "Moving to pay-as-you-go (OpEx) means no large upfront CapEx — you pay only for what you use. (Reconstructed from the question-list preview; this question was not shown in full during the recording.)" },
  { cat: "cloud", topic: "c_models", q: "Contoso Ltd. currently runs several business applications on physical servers in their on-premises datacenter. The company wants to modernize by migrating some applications to Azure while keeping others on-premises due to regulatory requirements. Contoso also needs users to authenticate seamlessly across both environments. Which cloud deployment model does this scenario describe?", options: ["Public cloud", "Community cloud", "Private cloud", "Hybrid cloud"], answer: 3, explain: "Keeping some workloads on-premises while moving others to Azure, with seamless authentication across both, describes a hybrid cloud." },
  { cat: "arch", topic: "a_core", q: "A company is planning to migrate their on-premises infrastructure to Azure. They need to assess their current environment of 50 physical servers running various workloads, multiple databases, and web applications. The IT manager wants to discover dependencies between servers, get Azure cost estimates, and receive right-sizing recommendations before migrating. Which Azure service should they use?", options: ["Azure Monitor", "Microsoft Defender for Cloud", "Azure Advisor", "Azure Migrate"], answer: 3, explain: "Azure Migrate is the central hub for discovering and assessing on-premises servers — dependency analysis, cost estimates, and right-sizing — before migration." },
  { cat: "arch", topic: "a_storage", q: "A company has five branch offices, each with a local Windows Server file server that stores frequently accessed project files. The IT department wants to centralize file storage in Azure Files while ensuring users at each branch can still access files quickly with low latency, even on a slow internet connection. Which Azure service should they implement?", options: ["Azure NetApp Files", "Azure Files with geo-replication", "Azure File Sync", "Azure Blob Storage with a Content Delivery Network (CDN)"], answer: 2, explain: "Azure File Sync centralizes shares in Azure Files while keeping a fast local cache on each branch's Windows Server." },
  { cat: "cloud", topic: "c_models", q: "A manufacturing company has servers in their on-premises datacenter, virtual machines in AWS, and resources in Azure. The IT director wants to use Azure management tools, apply Azure policies, and view all resources through a single control plane regardless of where they are located. Which Azure service should they implement?", options: ["Azure Monitor", "Azure Arc", "Azure Resource Manager", "Microsoft Defender for Cloud"], answer: 1, explain: "Azure Arc extends Azure management and governance to on-premises, multi-cloud, and edge resources through a single control plane." },
  { cat: "govern", topic: "g_cost", q: "An organization has deployed Azure resources across several departments (Marketing, Finance, and IT). The CFO needs monthly cost reports that break down Azure spending by department. What is the most effective way to accomplish this?", options: ["Use Microsoft Defender for Cloud to track departmental resource costs", "Apply tags with department names to resources and use cost analysis to filter and group spending by tag values", "Create separate resource groups for each department and manually calculate costs", "Create separate Azure subscriptions for each department and generate cost reports per subscription"], answer: 1, explain: "Tags are name/value metadata; applying a department tag and then grouping/filtering in Cost analysis produces per-department cost reports without restructuring resources." },
  { cat: "arch", topic: "a_storage", q: "A company is deploying a business-critical application to Azure that must remain available even if an entire Azure datacenter fails, but it does not need to survive a regional disaster. The solution must minimize cost. Which redundancy option should you recommend for the Azure Storage account?", options: ["Geo-redundant storage (GRS)", "Zone-redundant storage (ZRS)", "Geo-zone-redundant storage (GZRS)", "Locally redundant storage (LRS)"], answer: 1, explain: "ZRS replicates across three availability zones in the region, protecting against a datacenter (zone) failure without the cost of geo-replication." },
  { cat: "govern", topic: "g_gov", q: "A production resource group named RG-Prod contains critical virtual machines and storage accounts. The IT manager is concerned resources might be accidentally deleted by administrators who have Contributor access. You need to prevent accidental deletion while still allowing administrators to modify resource configurations. What should you implement?", options: ["Enable Microsoft Defender for Cloud on RG-Prod", "Remove Contributor permissions and assign Reader to all administrators", "Apply a Read-only lock on RG-Prod", "Apply a Delete lock (CanNotDelete) on RG-Prod"], answer: 3, explain: "A Delete (CanNotDelete) lock blocks deletion but still allows reading and modifying resources. A Read-only lock would also block the required modifications." },
  { cat: "govern", topic: "g_monitor", q: "A web application running on Azure App Service is experiencing slow page loads, but the team cannot determine which specific components are responsible. You need a monitoring solution that automatically detects performance anomalies, tracks user behavior, and identifies which dependencies cause slowdowns. Which Azure service should you recommend?", options: ["Microsoft Defender for Cloud", "Azure Monitor Logs", "Application Insights", "Azure Service Health"], answer: 2, explain: "Application Insights monitors live application performance, detects anomalies, tracks usage, and maps dependency slowdowns for developers." },
  { cat: "arch", topic: "a_identity", q: "Your organization wants users accessing cloud applications from outside the corporate network to perform multi-factor authentication (MFA), while users on the corporate network can sign in with just username and password. Which Microsoft Entra feature should you implement?", options: ["Microsoft Entra Multi-Factor Authentication", "Microsoft Entra Conditional Access", "Microsoft Entra Privileged Identity Management", "Microsoft Entra ID Protection"], answer: 1, explain: "Conditional Access applies access decisions based on signals such as location — e.g., requiring MFA only from outside the corporate network." },
  { cat: "cloud", topic: "c_cost", q: "A retail company currently manages its own datacenter with physical servers that often sit idle during off-peak hours. The company pays fixed costs for hardware, cooling, and maintenance regardless of actual usage. Which characteristic of cloud computing would most directly address their concern about paying for unused capacity?", options: ["High availability", "Geo-distribution", "Disaster recovery", "Pay-as-you-go pricing"], answer: 3, explain: "Pay-as-you-go (consumption-based) pricing means you pay only for resources you actually use, eliminating the cost of idle, over-provisioned capacity." },
  { cat: "arch", topic: "a_compute", q: "A development team needs to deploy a small application that processes incoming HTTP requests and performs simple data transformations. It runs only a few seconds per request and receives sporadic traffic throughout the day. The team wants to minimize infrastructure management and pay only for actual compute time used. Which Azure compute service should they choose?", options: ["Azure Virtual Machines", "Azure App Service", "Azure Functions", "Azure Container Instances"], answer: 2, explain: "Azure Functions is serverless and event-driven — ideal for short, sporadic tasks where you pay only per execution." },
  { cat: "govern", topic: "g_monitor", q: "A company has been running Azure resources for six months. The IT manager wants to identify opportunities to reduce costs, improve security, and optimize performance across all resources, based on actual usage and configuration. Which Azure service provides these personalized recommendations?", options: ["Azure Advisor", "Azure Monitor", "Microsoft Defender for Cloud", "Azure Service Health"], answer: 0, explain: "Azure Advisor analyzes your resources and gives personalized best-practice recommendations across cost, security, reliability, operational excellence, and performance." },
  { cat: "arch", topic: "a_compute", q: "A company wants to provide its 500 remote employees with secure, cloud-hosted Windows desktops and applications that can be accessed from any device, anywhere. Which Azure service should they use?", options: ["Azure Virtual Desktop", "Azure Virtual Machines", "Azure App Service", "Azure Container Instances"], answer: 0, explain: "Azure Virtual Desktop delivers virtualized Windows desktops and apps from the cloud to any device. (Reconstructed from the question-list preview; this question was not shown in full during the recording.)" },
  { cat: "arch", topic: "a_network", q: "Your company has two Azure virtual networks: VNet-Production in East US and VNet-Development in West Europe. The development team needs direct communication between virtual machines in both networks using private IP addresses. Which Azure networking solution should you implement?", options: ["Deploy Azure DNS to enable name resolution between the two networks", "Configure virtual network peering between VNet-Production and VNet-Development", "Configure an Azure VPN Gateway site-to-site connection between the two networks", "Create a shared subnet that spans both virtual networks"], answer: 1, explain: "VNet peering connects two virtual networks (even across regions) so resources communicate privately using private IPs over the Microsoft backbone." },
  { cat: "cloud", topic: "c_shared", q: "A company is migrating a web application to Azure that will run on Azure Virtual Machines (IaaS). The IT manager asks which security tasks remain the company's responsibility after migration. Which is the company responsible for managing?", options: ["Physical security of the datacenter hosting the virtual machines", "Security patches and updates for the operating system running on the virtual machines", "Security of the Azure hypervisor layer", "Physical network infrastructure connecting the Azure datacenter"], answer: 1, explain: "In IaaS, the customer manages the guest OS, including its security patches. Physical security, the hypervisor, and physical networking are Microsoft's responsibility." },
  { cat: "arch", topic: "a_compute", q: "A company is developing a new web application and wants to focus on writing code without managing the underlying infrastructure, operating system, or web server configuration. The solution must support automatic scaling based on traffic and provide built-in load balancing. Which Azure service should they use?", options: ["Azure Virtual Machines", "Azure Container Instances", "Azure Functions", "Azure App Service"], answer: 3, explain: "Azure App Service is a PaaS for hosting web apps with built-in autoscaling and load balancing, with no infrastructure or OS to manage." },
  { cat: "govern", topic: "g_gov", q: "Your organization has multiple Azure subscriptions across departments. Management requires that all virtual machines must have specific tags (Department, CostCenter, and Owner) applied before they can be created. Which Azure governance feature should you implement?", options: ["Management groups", "Azure Policy", "Resource locks", "Role-based access control (RBAC)"], answer: 1, explain: "Azure Policy enforces rules such as requiring specific tags, and can deny creation of non-compliant resources." },
  { cat: "govern", topic: "g_gov", q: "Your organization stores customer data across Azure SQL Database, Azure Storage accounts, and Azure Data Lake Storage. The compliance team needs to discover where sensitive personal information resides, classify it according to regulations, and track how data is accessed across all sources from a central location. Which Azure service should you recommend?", options: ["Microsoft Entra ID", "Microsoft Defender for Cloud", "Azure Policy", "Microsoft Purview"], answer: 3, explain: "Microsoft Purview is a unified data governance solution that discovers, classifies, and tracks sensitive data across many sources." },
  { cat: "arch", topic: "a_identity", q: "Your organization uses Microsoft Entra ID. You need to allow users from a partner company to access a specific application in your Azure environment without creating separate accounts for them, and the partner will manage their users' credentials and lifecycle. Which Microsoft Entra feature should you use?", options: ["Microsoft Entra B2B collaboration", "Microsoft Entra Domain Services", "Microsoft Entra B2C", "Microsoft Entra Conditional Access"], answer: 0, explain: "Microsoft Entra B2B collaboration lets external partners access your resources using their own existing credentials." },
  { cat: "cloud", topic: "c_types", q: "A company is developing a new web application and wants to minimize infrastructure management while keeping control over the application code and configuration. They need to deploy code directly without managing virtual machines, operating systems, or hardware. Which Azure service model best meets these requirements?", options: ["Platform as a Service (PaaS) using Azure App Service", "Infrastructure as a Service (IaaS) using Azure Virtual Machine Scale Sets", "Infrastructure as a Service (IaaS) using Azure Virtual Machines", "Software as a Service (SaaS) using Microsoft 365"], answer: 0, explain: "PaaS (Azure App Service) lets developers deploy code while Microsoft manages the OS, runtime, and infrastructure." },
  { cat: "cloud", topic: "c_benefits", q: "A retail company is migrating to Azure. The finance department needs to forecast annual cloud spending accurately for budget planning and wants to predict monthly costs within a 5% variance. Which benefit of cloud computing best addresses this requirement?", options: ["Disaster recovery", "Cost predictability", "Performance predictability", "High availability"], answer: 1, explain: "Cost predictability (aided by tools like Cost Management and the Pricing Calculator) lets organizations forecast and control cloud spend." },
  { cat: "govern", topic: "g_gov", q: "An organization has migrated several workloads to Azure. The IT security team needs to continuously assess the security posture of these resources, receive recommendations to improve security, and be alerted about potential threats. Which Azure service should they implement?", options: ["Azure Policy", "Microsoft Entra ID Protection", "Microsoft Defender for Cloud", "Azure Monitor"], answer: 2, explain: "Microsoft Defender for Cloud continuously assesses security posture, provides hardening recommendations, and alerts on threats." },
  { cat: "cloud", topic: "c_models", q: "Your organization is deploying a web application to Azure. The application must be accessible to users worldwide over the internet without requiring a VPN connection or private network configuration. Which cloud deployment model best describes this accessibility requirement?", options: ["Public cloud", "Private cloud", "Community cloud", "Hybrid cloud"], answer: 0, explain: "Public cloud delivers services over the public internet, accessible to anyone — ideal for a globally accessible app with no private networking requirement." },
  { cat: "arch", topic: "a_compute", q: "A software development company needs to deploy a web application that experiences unpredictable traffic spikes. The application consists of multiple microservices that must scale independently based on demand. The company wants to minimize infrastructure management while keeping the ability to package applications with their dependencies. Which Azure compute option best meets these requirements?", options: ["Azure Kubernetes Service (AKS) with auto-scaling enabled", "Azure Virtual Machines with manual scaling configuration", "Azure Container Instances with individual container deployment", "Azure App Service with single web app deployment"], answer: 0, explain: "AKS orchestrates containerized microservices that scale independently, packaged with their dependencies, with managed auto-scaling." },
  { cat: "arch", topic: "a_identity", q: "Your organization has 500 employees who need to access both Microsoft 365 applications and custom applications running in Azure. The IT department wants a centralized identity solution where users sign in once and access all applications without re-authenticating. Which Azure service should you recommend?", options: ["Azure Active Directory Domain Services (Azure AD DS)", "Microsoft Entra ID", "Azure Key Vault", "Windows Server Active Directory on Azure Virtual Machines"], answer: 1, explain: "Microsoft Entra ID provides centralized cloud identity with single sign-on across Microsoft 365 and Azure-integrated applications." },
  { cat: "govern", topic: "g_cost", q: "A company is considering migrating their on-premises infrastructure to Azure. They operate 50 physical servers with associated costs for hardware maintenance, electricity, cooling, and IT staff. The IT director wants to understand the potential cost savings over a 5-year period by comparing on-premises costs with equivalent Azure services. Which Azure tool should they use?", options: ["Total Cost of Ownership (TCO) Calculator", "Azure Pricing Calculator", "Azure Advisor", "Azure Cost Management and Billing"], answer: 0, explain: "The TCO Calculator estimates the savings of moving on-premises workloads to Azure by comparing current and projected costs." },
  { cat: "govern", topic: "g_gov", q: "A company is deploying a web application on Azure and the security team wants to implement the defense-in-depth model. The application uses Azure Virtual Machines, Azure SQL Database, and stores sensitive customer data. Which approach best demonstrates defense-in-depth?", options: ["Focus security efforts exclusively on the perimeter with a firewall and keep all VMs patched", "Configure RBAC for all resources and implement Microsoft Entra ID authentication for users", "Implement multiple layers of security including network security groups, encryption at rest, multi-factor authentication, and Microsoft Defender for Cloud monitoring", "Implement only network security groups (NSGs) with strict rules to control all traffic"], answer: 2, explain: "Defense-in-depth uses multiple, layered controls (network, identity, data encryption, monitoring) so no single layer's failure compromises the system." },
  { cat: "arch", topic: "a_compute", q: "A company is migrating an on-premises application server to Azure. The application requires 8 vCPUs, 32 GB of RAM, runs on Windows Server 2022, and needs full control over the operating system to install custom software. What should you recommend?", options: ["Azure Virtual Machines", "Azure Container Instances", "Azure Functions", "Azure App Service"], answer: 0, explain: "Azure Virtual Machines (IaaS) give full OS control to install custom software and meet specific VM sizing requirements." },
  { cat: "arch", topic: "a_compute", q: "A company is developing a mobile application that needs to process image uploads. The image-processing workload is unpredictable, with spikes occurring randomly throughout the day. The company wants to minimize costs by only paying for compute when images are actually being processed. Which Azure compute solution best meets these requirements?", options: ["Azure Functions with a consumption plan", "Azure App Service with an Always On feature", "Azure Container Instances running continuously", "Azure Virtual Machines with auto-scaling enabled"], answer: 0, explain: "Azure Functions on a consumption plan is serverless and event-driven — you pay only per execution, ideal for spiky, intermittent processing." },
  { cat: "govern", topic: "g_gov", q: "A resource group named RG-Production contains several virtual machines. You need User1 to be able to start and stop the VMs but not delete them or modify their configurations. What should you do?", options: ["Assign User1 the Reader role on RG-Production", "Create and assign User1 a custom Azure RBAC role scoped to RG-Production that allows only the required VM start and stop actions", "Assign User1 the Virtual Machine Contributor role on RG-Production", "Assign User1 the Contributor role on RG-Production"], answer: 1, explain: "A custom RBAC role granting only start/stop actions follows least privilege. Reader can't start/stop; VM Contributor and Contributor allow far more than needed." },
  { cat: "govern", topic: "g_cost", q: "A company is planning to migrate to Azure. They need to estimate the monthly cost of running 5 virtual machines, 2 Azure SQL databases, and 10 TB of Azure Blob Storage across two regions, before deploying any resources. Which Azure tool should the IT manager use?", options: ["Azure Advisor", "Total Cost of Ownership (TCO) Calculator", "Azure Cost Management and Billing", "Azure Pricing Calculator"], answer: 3, explain: "The Azure Pricing Calculator estimates the cost of services before you deploy them." },
  { cat: "govern", topic: "g_tools", q: "A development team currently deploys Azure resources by manually clicking through the Azure portal. The operations manager wants to improve consistency, reduce deployment errors, and version-control infrastructure configurations. Which approach should the team implement?", options: ["Assign multiple administrators to review each manual deployment before execution", "Use Azure Resource Manager (ARM) templates to define and deploy infrastructure", "Schedule regular backups of all Azure resources using Azure Backup", "Create detailed documentation with step-by-step portal screenshots"], answer: 1, explain: "ARM templates define infrastructure as code — repeatable, version-controllable deployments that reduce manual error." },
  { cat: "govern", topic: "g_gov", q: "Your organization needs to ensure that all Azure virtual machines deployed across multiple subscriptions are created only in specific regions (East US and West Europe) to comply with data-residency requirements. What should you use to enforce this?", options: ["Resource locks", "Microsoft Defender for Cloud", "Role-based access control (RBAC)", "Azure Policy"], answer: 3, explain: "Azure Policy can restrict the allowed locations/regions for resource deployment, enforcing data-residency requirements." },
  { cat: "govern", topic: "g_monitor", q: "A company runs multiple virtual machines in Azure that host a critical web application. The IT manager wants to be automatically notified via email whenever the CPU usage on any of these VMs exceeds 85% for more than 5 minutes. Which Azure Monitor capability should you configure?", options: ["A Log Analytics workspace query", "An Azure Monitor alert rule", "An Azure Monitor metrics chart", "An Application Insights availability test"], answer: 1, explain: "Azure Monitor alert rules trigger notifications or actions when a metric (like CPU) crosses a defined threshold for a set duration." },
  { cat: "cloud", topic: "c_benefits", q: "A retail company runs an e-commerce web application on Azure. During normal business hours it serves about 1,000 users, but during seasonal sales events traffic rises to 50,000 concurrent users. The company wants to handle these spikes while minimizing costs during normal periods. Which cloud capability best addresses this requirement?", options: ["Geo-distribution", "Vertical scaling (scaling up)", "High availability", "Horizontal scaling (scaling out)"], answer: 3, explain: "Horizontal scaling (scaling out) adds instances to handle spikes and removes them afterward, matching capacity to demand and minimizing cost when quiet." },
  { cat: "govern", topic: "g_cost", q: "A company is migrating to Azure. They have a development environment used only during business hours (9 AM–5 PM, Mon–Fri) and a production environment that must run continuously. The IT manager wants the greatest cost savings for the development environment. Which approach should they implement?", options: ["Reserved instances with a one-year commitment for the development VMs", "Reserved instances with a three-year commitment for the development VMs", "Azure Hybrid Benefit using existing on-premises licenses", "Pay-as-you-go pricing with automated shutdown and startup schedules for the development VMs"], answer: 3, explain: "For an environment used only part of the time, pay-as-you-go with scheduled auto-shutdown avoids paying for idle compute — the biggest saving here." },
  { cat: "arch", topic: "a_identity", q: "Your company wants to improve security for users accessing Microsoft Entra ID-protected resources. The IT director wants an authentication method that eliminates the need to remember and enter passwords while still providing strong authentication. Which method should you recommend?", options: ["Username and complex password with regular rotation", "Multi-factor authentication using SMS text messages", "Security questions and answers", "Windows Hello for Business"], answer: 3, explain: "Windows Hello for Business provides passwordless, strong authentication using biometrics or a PIN tied to device hardware." },
  { cat: "cloud", topic: "c_shared", q: "A retail company is migrating its e-commerce application to Azure. The IT director is concerned about protecting customer data and maintaining compliance, and asks how Azure's built-in security can reduce their security management burden compared to on-premises. Which benefit best addresses this concern?", options: ["Azure eliminates all security responsibilities from the customer by handling every aspect of the cloud environment", "Azure provides security tools and features that are managed and updated by Microsoft, reducing the organization's responsibility for maintaining security infrastructure", "Azure requires customers to install and maintain their own security software on all virtual machines", "Azure transfers all compliance obligations to the customer"], answer: 1, explain: "Under shared responsibility, Microsoft manages and updates the underlying security of the cloud platform, reducing (but not eliminating) the customer's burden." },
  { cat: "arch", topic: "a_core", q: "A company is deploying a business-critical application in Azure that must remain available even if an entire Azure region becomes unavailable due to a natural disaster. They need Azure to automatically replicate certain platform services to a secondary location for disaster recovery. Which Azure feature provides this geographic redundancy?", options: ["Availability Sets in multiple regions", "Resource groups spanning multiple regions", "Availability Zones within a single region", "Azure region pairs"], answer: 3, explain: "Azure region pairs provide cross-region replication and prioritized recovery for disaster recovery; Availability Zones protect only within one region." },
  { cat: "govern", topic: "g_tools", q: "Your organization needs to deploy identical development, testing, and production environments in Azure, each containing the same virtual machines, storage accounts, and virtual networks with identical configurations. The IT manager wants consistency and to minimize manual configuration errors. Which Azure feature should you recommend?", options: ["Azure Resource Manager (ARM) templates", "Azure Policy", "Azure Portal dashboard", "Resource groups"], answer: 0, explain: "ARM templates define infrastructure as code, enabling consistent, repeatable deployment of identical environments." },
  { cat: "govern", topic: "g_tools", q: "Your organization needs to deploy 15 identical virtual machines across three different Azure regions for a new application. The IT manager wants to ensure consistency in configuration and simplify the deployment process. Which Azure Resource Manager capability is most appropriate?", options: ["Use ARM locks to prevent changes to the VMs after deployment", "Use ARM resource groups to organize the VMs by region", "Use ARM role-based access control (RBAC) to manage permissions for the VMs", "Use ARM templates to define the infrastructure and deploy it consistently across all regions"], answer: 3, explain: "ARM templates enable repeatable, consistent, automated deployment of identical resources across regions." },
  { cat: "govern", topic: "g_tools", q: "An IT manager asks you to demonstrate how to quickly find and deploy an Azure Virtual Machine without using command-line tools or scripts, using a graphical interface that works from any web browser without installing software. Which Azure management tool should you demonstrate?", options: ["Azure PowerShell", "Azure Mobile App", "Azure Portal", "Azure CLI"], answer: 2, explain: "The Azure portal is the web-based graphical interface for building and managing resources, requiring no installation." },
  { cat: "arch", topic: "a_identity", q: "A retail company wants to build a mobile application that lets customers create accounts and sign in using social media credentials (Facebook, Google) or email, and manage their shopping profiles, without requiring corporate credentials. Which Azure identity service should they implement?", options: ["Microsoft Entra ID B2B (Business-to-Business)", "Microsoft Entra ID B2C (Business-to-Consumer)", "Microsoft Entra ID (standard tenant)", "Microsoft Entra Domain Services"], answer: 1, explain: "Microsoft Entra ID B2C handles customer/consumer identity at scale, supporting sign-up/sign-in with email or social identity providers." },
  { cat: "arch", topic: "a_core", q: "A retail company runs a critical e-commerce application that must remain available to customers even if an Azure datacenter experiences an outage. They want to leverage Azure's infrastructure to keep the application operating during such failures. Which Azure reliability benefit directly addresses this?", options: ["Azure's ability to deploy resources across multiple availability zones within a region", "Azure's compliance certifications that meet industry standards", "Azure's pay-as-you-go pricing model", "Azure's support for automatic horizontal scaling"], answer: 0, explain: "Deploying across multiple availability zones keeps the application running if a single datacenter (zone) fails." },
  { cat: "cloud", topic: "c_cost", q: "A company is migrating from an on-premises datacenter to Azure. Currently they pay fixed monthly costs regardless of usage. Which statement best describes how the consumption-based model in Azure will change their cost structure?", options: ["They will pay a fixed monthly subscription fee similar to their current datacenter costs", "They will pay upfront capital expenses for Azure infrastructure before deploying", "They will pay the same total costs, just spread across multiple subscriptions", "They will pay only for the Azure resources they actually use, with costs varying based on consumption"], answer: 3, explain: "The consumption-based model charges only for resources actually used, so costs vary with demand rather than being fixed." },
  { cat: "govern", topic: "g_monitor", q: "An organization runs multiple web applications across several Azure regions. The IT manager wants to be notified when Azure plans maintenance that might affect the company's virtual machines, and to review root cause analyses when service interruptions occur. Which Azure service should you recommend?", options: ["Azure Advisor", "Azure Service Health", "Microsoft Defender for Cloud", "Azure Monitor"], answer: 1, explain: "Azure Service Health provides personalized notifications about planned maintenance, outages, and post-incident root cause analyses for the services you use." },
  { cat: "arch", topic: "a_storage", q: "A company needs to store large amounts of unstructured data (images, videos, log files) for their web application. The data is accessed frequently during the first month after upload but rarely afterward. They want to minimize storage costs while keeping the data available. Which solution should they implement?", options: ["Azure Queue Storage with automatic archiving", "Azure Table Storage partitioned by upload date", "Azure Files with a Premium tier for the first month, then Standard", "Azure Blob Storage with a lifecycle management policy to move data to the Cool access tier after 30 days"], answer: 3, explain: "Blob storage handles unstructured data; a lifecycle policy can automatically move blobs from Hot to Cool after 30 days to cut costs while keeping them accessible." },
  { cat: "arch", topic: "a_core", q: "A company is deploying a business-critical application that needs to be protected against datacenter-level failures within a single Azure region and requires a 99.99% availability SLA. Which Azure feature should they use to distribute their virtual machines across physically separate locations within the region?", options: ["Deploy virtual machines across multiple Azure regions", "Deploy virtual machines in a single datacenter with multiple backup copies", "Deploy virtual machines across multiple resource groups", "Deploy virtual machines across availability zones"], answer: 3, explain: "Availability Zones are physically separate datacenters within a region; spreading VMs across zones provides the higher (99.99%) SLA and datacenter-fault protection." },
  { cat: "cloud", topic: "c_models", q: "A U.S. government agency needs to deploy Azure services to host applications processing sensitive federal data. The agency must comply with regulations requiring physical and logical isolation within the United States, screened U.S. personnel for operations, and FedRAMP High compliance. Which Azure deployment option should they select?", options: ["Deploy resources in Azure public cloud regions in the United States (such as East US or West US)", "Deploy resources using Azure Arc on the agency's on-premises infrastructure", "Deploy resources in Azure China regions operated by 21Vianet", "Deploy resources in Azure Government"], answer: 3, explain: "Azure Government is a sovereign, isolated cloud for U.S. government workloads, with screened U.S. personnel and FedRAMP High compliance." },

  /* ============================ SET 2 ============================ */

  { cat: "arch", topic: "a_compute", q: "A developer needs to deploy a web application built using .NET 8.0. It must be deployed quickly without managing the underlying operating system or runtime, must automatically handle patching and infrastructure, and must support custom domain names and SSL certificates. Which Azure service should the developer use?", options: ["Azure Virtual Machines", "Azure Functions", "Azure App Service", "Azure Container Instances"], answer: 2, explain: "Azure App Service is a PaaS that hosts web apps with managed OS/runtime, automatic patching, custom domains, and SSL — no infrastructure management. (This question was captured from a later frame of the recording.)" },
  { cat: "cloud", topic: "c_benefits", q: "A retail company runs its e-commerce application on Azure. During a regional power outage, the application automatically failed over to another Azure region and customers continued placing orders without interruption. Which benefit of cloud computing does this primarily demonstrate?", options: ["Predictability", "Scalability", "Reliability", "Manageability"], answer: 2, explain: "Reliability is the ability to recover from failures and keep functioning — here, automatic failover kept the app available during an outage." },
  { cat: "govern", topic: "g_tools", q: "A system administrator needs to quickly create multiple Azure storage accounts across resource groups using a consistent naming convention, but does not have permission to install software on their local workstation. Which tool allows them to run Azure CLI commands without installing anything locally?", options: ["The Azure PowerShell module installed from the PowerShell Gallery", "Azure Cloud Shell accessed through the Azure portal", "Azure CLI installed using the MSI installer on Windows", "Visual Studio Code with the Azure CLI extension"], answer: 1, explain: "Azure Cloud Shell is a browser-based shell (Bash or PowerShell) accessed via the portal — no local installation required." },
  { cat: "arch", topic: "a_core", q: "Your company is deploying a mission-critical application that must maintain availability even if an entire Azure datacenter becomes unavailable due to a natural disaster. Customer data must be automatically replicated to a geographically distant location for business continuity. Which Azure feature should you rely on for geographic redundancy?", options: ["Resource Groups", "Availability Zones", "Region Pairs", "Availability Sets"], answer: 2, explain: "Region pairs replicate data to a geographically distant paired region (300+ miles) for disaster recovery; Availability Zones only protect within one region." },
  { cat: "arch", topic: "a_identity", q: "A company wants to improve security by eliminating passwords. The IT department needs a solution that lets users sign in to Microsoft Entra ID using biometric data or a PIN stored on their device's hardware security module. Which passwordless authentication method should they implement?", options: ["Shared access signatures (SAS)", "Security questions and answers", "Multi-factor authentication (MFA) with SMS verification", "Windows Hello for Business"], answer: 3, explain: "Windows Hello for Business enables passwordless sign-in using biometrics or a PIN bound to the device's hardware security." },
  { cat: "govern", topic: "g_gov", q: "A production resource group contains critical virtual machines and storage accounts. The IT manager is concerned administrators might accidentally delete these resources during routine maintenance. You need to prevent accidental deletion while still allowing authorized administrators to modify configurations when needed. What should you implement?", options: ["Configure RBAC to remove delete permissions from all administrators", "Apply a Read-only lock to the resource group", "Enable Microsoft Defender for Cloud to protect the resources", "Apply a Delete lock (CanNotDelete) to the resource group"], answer: 3, explain: "A Delete (CanNotDelete) lock prevents deletion while still allowing modification; a Read-only lock would block the required changes." },
  { cat: "arch", topic: "a_storage", q: "A company needs to store 500 TB of archived financial records that must be retained for 7 years for regulatory compliance. The data will rarely be accessed, but when needed the company can tolerate a retrieval delay of several hours. They want to minimize storage costs while ensuring durability. Which Azure Storage access tier should they use?", options: ["Cool access tier", "Archive access tier", "Hot access tier", "Cold access tier"], answer: 1, explain: "The Archive tier offers the lowest storage cost for rarely accessed, long-term data and tolerates retrieval latency (rehydration) of hours." },
  { cat: "cloud", topic: "c_benefits", q: "A company currently manages its on-premises infrastructure manually, with IT staff logging into individual servers to apply updates, configure settings, and monitor performance. After migrating to Azure they want to reduce this manual effort. Which Azure capability best demonstrates the cloud benefit of manageability?", options: ["Storing backup data in geo-redundant storage to protect against regional failures", "Using Azure Reserved Instances to reduce VM costs", "Deploying resources across multiple regions to improve availability", "Using Azure Policy to automatically enforce configuration standards across all resources without manual intervention"], answer: 3, explain: "Manageability in the cloud includes automating governance — e.g., Azure Policy enforcing configuration standards automatically, removing per-server manual work." },
  { cat: "arch", topic: "a_identity", q: "Your organization has 500 employees who need to access both Microsoft 365 applications and Azure resources. The IT department wants a centralized identity solution where users sign in once and access all required resources without additional authentication prompts. Which Azure service should you recommend?", options: ["Azure Key Vault", "Azure Active Directory Domain Services (Azure AD DS)", "Azure Virtual Network", "Microsoft Entra ID"], answer: 3, explain: "Microsoft Entra ID provides centralized cloud identity and single sign-on across Microsoft 365 and Azure resources." },
  { cat: "arch", topic: "a_storage", q: "A company stores 500 GB of product images in an Azure Storage account. The images are accessed frequently during the first month after upload for marketing campaigns, but rarely afterward. They must remain available for immediate retrieval when needed. Which storage tier is most cost-effective for storing these images after the initial month?", options: ["Hot tier", "Cold tier", "Cool tier", "Archive tier"], answer: 2, explain: "The Cool tier suits infrequently accessed data (≥30 days) that still needs immediate, online retrieval. Archive would require rehydration, so it's not suitable for immediate access." },
  { cat: "arch", topic: "a_network", q: "Your company has two Azure virtual networks: VNet-Production in East US hosting business-critical applications, and VNet-Development in West Europe used by developers. Developers need to access resources in the production network for testing, but the two networks currently cannot communicate. What should you implement to enable connectivity between them?", options: ["Configure Azure virtual network peering between VNet-Production and VNet-Development", "Configure a Network Security Group (NSG) rule to allow traffic between the regions", "Create a shared subnet that spans both virtual networks", "Deploy Azure DNS zones in both virtual networks"], answer: 0, explain: "VNet peering connects two virtual networks (even across regions) so resources can communicate privately over the Microsoft backbone." },
  { cat: "govern", topic: "g_gov", q: "Your company has VMs across three resource groups: RG-Development, RG-Testing, and RG-Production. A developer needs to start and stop VMs in RG-Development and RG-Testing, but must not be able to create new VMs or modify any resources in RG-Production. What is the most efficient way to grant these permissions using Azure RBAC?", options: ["Assign the developer the Contributor role on RG-Development and RG-Testing", "Assign the developer the Reader role on all three resource groups and the Owner role on RG-Development and RG-Testing", "Assign the developer the Virtual Machine Contributor role at the subscription level", "Assign the developer the Virtual Machine Contributor role on RG-Development and RG-Testing"], answer: 3, explain: "Scoping the Virtual Machine Contributor role to only RG-Development and RG-Testing grants VM management there while leaving RG-Production untouched — least privilege at the right scope." },
  { cat: "arch", topic: "a_core", q: "A company is deploying a web application to Azure that requires virtual machines, a load balancer, network security groups, and a virtual network. The IT manager wants to organize these components logically and manage their lifecycle together. What should you use?", options: ["A management group", "An Azure subscription", "An Azure region", "A resource group"], answer: 3, explain: "A resource group is a logical container for related resources that are deployed, managed, and deleted together." },
  { cat: "govern", topic: "g_gov", q: "Your organization needs to ensure that all Azure virtual machines created across the company comply with corporate standards — for example, only approved VM sizes and required tags — and that non-compliant VMs are blocked at creation. Which Azure governance feature should you implement?", options: ["Azure Policy", "Role-based access control (RBAC)", "Resource locks", "Management groups"], answer: 0, explain: "Azure Policy enforces and audits resource compliance (allowed sizes, required tags, etc.) and can deny non-compliant deployments. (Reconstructed from the question-list preview; this question was not shown in full during the recording.)" },
  { cat: "arch", topic: "a_identity", q: "A retail company is developing a mobile shopping application that lets customers create accounts using their email addresses or social media credentials (Facebook, Google). It needs secure authentication and profile management for millions of consumer users. Which Azure service should they implement?", options: ["Microsoft Entra Domain Services", "Microsoft Entra ID B2C (Business-to-Consumer)", "Microsoft Entra ID B2B (Business-to-Business)", "Azure Active Directory Connect"], answer: 1, explain: "Microsoft Entra ID B2C provides scalable consumer identity with email and social sign-in." },
  { cat: "cloud", topic: "c_models", q: "A retail company runs its inventory management system on servers in its own datacenter. They want to migrate their customer-facing web application to Azure while keeping the inventory system on-premises due to compliance requirements, and the two systems must communicate securely. Which cloud deployment model does this describe?", options: ["Hybrid cloud", "Community cloud", "Private cloud", "Public cloud"], answer: 0, explain: "Combining on-premises systems with Azure-hosted workloads that communicate securely is a hybrid cloud." },
  { cat: "arch", topic: "a_compute", q: "A company is developing a serverless application that must execute code to process and resize images whenever a new image is uploaded to Azure Blob Storage. The code should run automatically without managing infrastructure, and they should pay only for actual execution time. Which Azure service should they use?", options: ["Azure Virtual Machines", "Azure App Service", "Azure Functions", "Azure Container Instances"], answer: 2, explain: "Azure Functions is serverless and event-driven — it can trigger on a blob upload and bills only for execution time." },
  { cat: "arch", topic: "a_core", q: "The Finance department needs to deploy 15 virtual machines, 3 storage accounts, and 2 SQL databases for a quarterly reporting application. All resources must be managed together and will be deleted at the end of the fiscal year. What is the most appropriate way to organize them according to Azure's hierarchy?", options: ["Create a new Azure subscription specifically for these resources", "Deploy resources into separate resource groups, one per resource type", "Deploy all resources directly under the management group without resource groups", "Deploy all resources into a single resource group dedicated to the quarterly reporting application"], answer: 3, explain: "Resources sharing the same lifecycle (deployed and deleted together) should go in a single resource group; deleting it removes them all at once." },
  { cat: "cloud", topic: "c_types", q: "A development team needs to deploy a web application to Azure. They want to focus on writing code and managing the application without configuring or maintaining the underlying operating system, web server software, or security patches. Which Azure service model should they choose?", options: ["Infrastructure as a Service (IaaS) using Azure Virtual Machine Scale Sets", "Infrastructure as a Service (IaaS) using Azure Virtual Machines", "Platform as a Service (PaaS) using Azure App Service", "Software as a Service (SaaS) using Microsoft 365"], answer: 2, explain: "PaaS (Azure App Service) lets the team manage only the app while Microsoft handles the OS, web server, and patching." },
  { cat: "arch", topic: "a_storage", q: "A company needs to store 500 TB of archived financial records retained for 7 years for compliance. The data is rarely accessed, but when needed the company can tolerate a retrieval delay of several hours. Which Azure storage solution is most cost-effective?", options: ["Azure Blob Storage with the Cool access tier", "Azure Blob Storage with the Hot access tier", "Azure Blob Storage with the Archive access tier", "Azure Files with the Premium performance tier"], answer: 2, explain: "The Archive tier offers the lowest cost for rarely accessed, long-term archival data where hours of retrieval latency is acceptable." },
  { cat: "cloud", topic: "c_models", q: "Your company is deploying a new web application in Azure that must be accessible to all internet users worldwide without any authentication requirements. Which type of cloud deployment should you recommend for hosting the front-end resources?", options: ["Public cloud", "Hybrid cloud", "Community cloud", "Private cloud"], answer: 0, explain: "A globally accessible, publicly available application is best hosted in the public cloud." },
  { cat: "govern", topic: "g_cost", q: "A retail company is considering migrating their on-premises infrastructure to Azure. They operate 50 physical servers with costs for power, cooling, hardware maintenance, and IT staff. The CFO wants to understand potential cost savings over a 3-year period before deciding. Which Azure tool should they use to compare current on-premises costs against projected Azure costs?", options: ["Microsoft Cost Management and Billing", "Azure Pricing Calculator", "Azure Advisor", "Total Cost of Ownership (TCO) Calculator"], answer: 3, explain: "The TCO Calculator compares the cost of running workloads on-premises versus in Azure to estimate savings." },
  { cat: "arch", topic: "a_core", q: "A company is deploying a business-critical application in the East US Azure region. It must remain available even if a datacenter failure occurs within the region, while maintaining low-latency access for users in the eastern United States. Which Azure feature should you implement?", options: ["Deploy the application across multiple availability zones within the East US region", "Deploy the application to multiple Azure regions such as East US and West Europe", "Deploy the application using a single availability zone in the East US region", "Deploy the application across multiple resource groups within the East US region"], answer: 0, explain: "Availability Zones provide datacenter-fault protection within a region while keeping users' traffic local for low latency." },
  { cat: "arch", topic: "a_storage", q: "A company needs to upload 500 GB of image files from an on-premises server to an Azure Storage account. The IT manager requires a solution that can resume interrupted uploads automatically and can be scheduled to run during off-peak hours using scripts. Which tool should you recommend?", options: ["AzCopy", "Azure PowerShell with Set-AzStorageBlob", "Azure Portal", "Azure Storage Explorer"], answer: 0, explain: "AzCopy is a scriptable command-line tool optimized for high-performance, resumable bulk copying of data to/from Azure Storage." },
  { cat: "arch", topic: "a_compute", q: "A company is deploying a web application on Azure Virtual Machines. The application has predictable usage — high traffic during business hours (8 AM–6 PM, Mon–Fri) and minimal traffic during evenings and weekends. Which Azure feature would most effectively reduce costs while maintaining performance during peak hours?", options: ["Permanently reduce the size of the virtual machines to a smaller tier", "Purchase Azure Reserved Virtual Machine Instances for a 3-year commitment", "Move the virtual machines to a different Azure region with lower pricing", "Implement Azure Virtual Machine Scale Sets with autoscaling rules based on CPU utilization"], answer: 3, explain: "VM Scale Sets with autoscaling add instances during peak demand and remove them when idle, reducing cost while maintaining peak performance." },
  { cat: "cloud", topic: "c_cost", q: "A company is migrating from an on-premises datacenter to Azure. They own physical servers purchased three years ago for $500,000 and pay for power, cooling, and maintenance regardless of usage. How will moving to Azure's consumption-based model change their cost structure?", options: ["They will need to purchase Azure servers upfront and pay monthly maintenance based on the number of servers", "They will pay only for the Azure resources they actually use, with the ability to scale resources up or down based on demand", "They will pay reduced fixed costs because of Azure's economies of scale, but costs remain constant regardless of usage", "They will continue paying the same fixed costs as on-premises"], answer: 1, explain: "The consumption-based model charges only for what you use and lets you scale on demand — replacing fixed, usage-independent costs." },
  { cat: "arch", topic: "a_storage", q: "A company stores critical financial data in Azure Storage accounts. They require protection against datacenter-level failures within a region but do not need protection against region-wide outages, and they want to minimize cost. Which Azure Storage redundancy option should they select?", options: ["Locally redundant storage (LRS)", "Geo-zone-redundant storage (GZRS)", "Geo-redundant storage (GRS)", "Zone-redundant storage (ZRS)"], answer: 3, explain: "ZRS replicates synchronously across three availability zones in the region — datacenter-fault protection without the cost of geo-replication." },
  { cat: "arch", topic: "a_core", q: "An organization is deploying a three-tier web application (web server, application server, and database server). The IT manager wants to organize these resources so they can be managed together, and when the project ends all related resources can be removed in a single operation. What is the recommended approach?", options: ["Create separate resource groups for each server tier and link them with tags", "Create a single resource group for all three tiers and deploy all application resources into it", "Create a management group containing all the servers and their resources", "Deploy all resources into the default resource group associated with the subscription"], answer: 1, explain: "Placing resources that share a lifecycle in one resource group lets you manage and delete them together in a single operation." },
  { cat: "govern", topic: "g_gov", q: "Your organization stores customer data across multiple Azure subscriptions, on-premises SQL servers, and third-party SaaS applications. The compliance team needs to automatically discover where sensitive data resides, classify it according to regulations, and track data lineage across all sources from a single location. Which Azure service should you recommend?", options: ["Azure Policy", "Microsoft Defender for Cloud", "Microsoft Purview", "Microsoft Entra ID"], answer: 2, explain: "Microsoft Purview is a unified data governance solution that discovers, classifies, and tracks data (including lineage) across cloud, on-premises, and SaaS sources." },
  { cat: "arch", topic: "a_core", q: "You are deploying a new Azure Virtual Machine to host a web application using default portal settings. Which of the following resources is NOT automatically created as part of the VM deployment?", options: ["Network Interface Card (NIC)", "Operating system disk", "Virtual Network (VNet)", "Azure Backup vault"], answer: 3, explain: "Deploying a VM automatically provisions a NIC, OS disk, and VNet (if none exists). An Azure Backup (Recovery Services) vault is a separate resource you must create to enable backup." },
  { cat: "govern", topic: "g_tools", q: "An IT administrator needs to automate the creation of 50 virtual machines across multiple Azure subscriptions. They are comfortable with command-line tools and want a solution that provides access to Azure Resource Manager capabilities through cmdlets and works on Windows, macOS, and Linux. Which tool should they use?", options: ["Azure Cloud Shell", "Azure PowerShell", "Azure CLI", "Azure portal"], answer: 1, explain: "Azure PowerShell provides cross-platform management through cmdlets (Verb-Noun) that call Azure Resource Manager." },
  { cat: "arch", topic: "a_storage", q: "A manufacturing company needs to migrate 80 TB of historical production data from their on-premises datacenter to Azure Blob Storage. The datacenter has limited internet bandwidth of 100 Mbps, and they want to complete the migration within one week while minimizing cost and avoiding impact on daily operations. Which Azure service should they use?", options: ["Azure Data Box", "Azure ExpressRoute", "Azure File Sync", "Azure Storage Explorer"], answer: 0, explain: "Azure Data Box is a physical appliance for offline bulk transfer — far faster than 80 TB over a 100 Mbps link, without saturating the network." },
  { cat: "arch", topic: "a_network", q: "A financial services company needs to establish a connection between their on-premises datacenter and Azure. They require a private, dedicated connection that does not traverse the public internet due to regulatory compliance, with predictable performance and bandwidth up to 100 Gbps. Which Azure networking service should they implement?", options: ["Azure ExpressRoute", "Azure Virtual WAN", "Azure Bastion", "Azure VPN Gateway"], answer: 0, explain: "Azure ExpressRoute provides a private, dedicated, high-bandwidth connection that bypasses the public internet." },
  { cat: "arch", topic: "a_identity", q: "Your company uses Microsoft Entra ID. You need to provide external partners from multiple organizations access to a specific SharePoint site and Microsoft Teams channel for a joint project. The partners should use their existing corporate credentials, and your IT team should maintain control over access permissions. Which Microsoft Entra feature should you implement?", options: ["Microsoft Entra B2B collaboration", "Microsoft Entra B2C (Business-to-Consumer)", "Guest access through new Microsoft Entra ID accounts", "Microsoft Entra Domain Services"], answer: 0, explain: "Microsoft Entra B2B collaboration lets external partners use their own credentials while your organization controls access to shared resources." },
  { cat: "arch", topic: "a_identity", q: "Your organization wants users accessing sensitive financial applications from outside the corporate network to use multi-factor authentication (MFA), while users accessing the same applications from within the office network only need username and password. Which Microsoft Entra feature should you implement?", options: ["Microsoft Entra Conditional Access", "Microsoft Entra Privileged Identity Management", "Microsoft Entra ID Protection", "Microsoft Entra Domain Services"], answer: 0, explain: "Conditional Access evaluates signals such as network location and can require MFA only when users connect from outside the corporate network." },
  { cat: "arch", topic: "a_core", q: "Your organization has separate development, testing, and production environments in Azure. The finance department requires detailed cost tracking and billing separation for each environment, different teams need administrative control over their respective environments, and all environments must use the same Microsoft Entra ID tenant. What is the recommended approach?", options: ["Create separate Microsoft Entra ID tenants for each environment with their own subscriptions", "Create separate management groups for each environment within a single subscription", "Create separate Azure subscriptions for each environment under the same Microsoft Entra ID tenant", "Create separate resource groups for each environment within a single subscription"], answer: 2, explain: "Subscriptions are the billing and access boundary; separate subscriptions under one tenant give per-environment billing separation and independent administrative control while sharing identity." },
  { cat: "cloud", topic: "c_types", q: "A company wants to provide email and collaboration services to its 500 employees without managing any underlying infrastructure or software updates. The solution must be accessible from any device with an internet connection, with a monthly per-user subscription fee. Which cloud service model best meets these requirements?", options: ["Platform as a Service (PaaS)", "Infrastructure as a Service (IaaS)", "On-premises deployment", "Software as a Service (SaaS)"], answer: 3, explain: "Ready-to-use, fully managed software billed per user (like Microsoft 365) is Software as a Service (SaaS)." },
  { cat: "cloud", topic: "c_cost", q: "A manufacturing company maintains its own datacenter with physical servers running at 30% average utilization, and pays for electricity, cooling, hardware maintenance, and 24/7 IT staff. The CTO is considering moving to Azure. Which characteristic of cloud computing would provide the most immediate cost benefit?", options: ["Ability to deploy applications using infrastructure-as-code templates", "Pay only for the compute resources actually consumed instead of maintaining underutilized physical hardware", "Access to the latest hardware without purchasing new equipment", "High availability through automatic failover to multiple regions"], answer: 1, explain: "With 30% utilization, the biggest immediate saving comes from consumption-based pricing — paying only for what's used instead of funding idle hardware." },
  { cat: "govern", topic: "g_tools", q: "Your company currently deploys Azure resources manually through the Azure portal. The IT manager wants to improve deployment consistency, reduce human error, and enable the team to version-control infrastructure configurations. Which approach best addresses these requirements?", options: ["Use Azure Resource Manager (ARM) templates or Bicep files to define infrastructure in code, stored in a version control system and deployed repeatedly", "Assign multiple administrators to review each other's work when manually creating resources", "Create detailed documentation with screenshots and store it in a SharePoint library", "Create a video tutorial demonstrating portal deployment for all team members"], answer: 0, explain: "Infrastructure as Code (ARM templates or Bicep) is declarative, repeatable, and version-controllable — reducing human error." },
  { cat: "govern", topic: "g_gov", q: "Your organization has deployed multiple Azure virtual machines and storage accounts across several subscriptions. The IT security team needs a centralized solution to assess security vulnerabilities, provide recommendations to strengthen the security posture, and receive alerts about potential threats across all Azure resources. Which Azure service should you recommend?", options: ["Azure Monitor", "Microsoft Entra ID Protection", "Microsoft Defender for Cloud", "Microsoft Purview"], answer: 2, explain: "Microsoft Defender for Cloud centrally assesses security posture, recommends improvements, and alerts on threats across subscriptions." },
  { cat: "govern", topic: "g_cost", q: "A retail company is migrating to Azure and will run multiple virtual machines for their web application. Usage varies significantly — peak demand during holiday seasons (November–December) and minimal usage other months. The finance team wants to optimize costs while keeping the ability to scale quickly during peaks. Which pricing approach is most cost-effective?", options: ["Purchase Azure Reserved VM Instances with a 3-year commitment for all required VMs", "Purchase Reserved VM Instances for baseline capacity and use pay-as-you-go pricing for additional capacity during peak periods", "Use pay-as-you-go pricing and scale VMs up and down based on demand throughout the year", "Run all VMs continuously at peak capacity year-round"], answer: 1, explain: "Combining Reserved Instances for steady baseline load with pay-as-you-go for seasonal bursts optimizes cost while preserving the ability to scale." },
  { cat: "govern", topic: "g_monitor", q: "Your company runs web applications across three Azure regions (East US, West Europe, and Southeast Asia). This morning, users in Europe reported intermittent connectivity issues. You need to determine whether there is an ongoing Azure platform issue affecting your resources in West Europe and receive notifications about similar issues in the future. Which Azure service should you use?", options: ["Microsoft Defender for Cloud", "Azure Service Health", "Azure Monitor", "Azure Advisor"], answer: 1, explain: "Azure Service Health reports Azure platform issues affecting the regions/services you use and can notify you of future incidents." },
  { cat: "arch", topic: "a_storage", q: "A company needs to store 500 TB of archived financial records retained for 7 years for compliance. The data will rarely be accessed, but when needed they can tolerate a retrieval delay of several hours. The solution must minimize storage cost while ensuring durability. Which storage service and access tier should you recommend?", options: ["Azure Blob Storage with the Archive access tier", "Azure Blob Storage with the Hot access tier", "Azure Files with the Premium performance tier", "Azure Queue Storage with geo-redundant replication"], answer: 0, explain: "Blob Storage with the Archive tier provides the lowest-cost durable storage for rarely accessed, long-term data tolerant of retrieval latency." },
  { cat: "cloud", topic: "c_shared", q: "Your company is deploying a web application using Azure Virtual Machines. The security team wants to understand who is responsible for various security aspects under the shared responsibility model. Which security task is Microsoft's responsibility in this scenario?", options: ["Managing the physical security of the datacenter where the virtual machines are hosted", "Ensuring the network security group (NSG) rules are properly configured to restrict traffic to the virtual machines", "Configuring access permissions for users who can manage the virtual machines through Microsoft Entra ID", "Installing and maintaining antimalware software on the guest operating system of the virtual machines"], answer: 0, explain: "Physical datacenter, hosts, and network are always Microsoft's responsibility. With IaaS VMs, NSGs, identity config, and guest-OS antimalware are the customer's." },
  { cat: "govern", topic: "g_tools", q: "Your company needs to deploy identical development, testing, and production environments in Azure, each containing the same virtual machines, storage accounts, and virtual networks with consistent configurations. The IT manager wants all environments to be recreated quickly and identically if needed. Which Azure feature should you recommend?", options: ["Azure Cloud Shell", "Azure Monitor workbooks", "Azure Resource Manager (ARM) templates", "Azure Portal dashboard"], answer: 2, explain: "ARM templates define infrastructure as code, allowing identical environments to be recreated quickly and consistently." },
  { cat: "govern", topic: "g_gov", q: "Your organization has 15 Azure subscriptions used by different departments. The CFO requires that all subscriptions have a spending limit policy applied, and the security team needs all subscriptions to comply with the company's resource tagging standards. What is the most efficient way to apply these requirements across all current and future subscriptions?", options: ["Use Microsoft Entra ID to create a security group and assign policies to all subscriptions", "Create a resource group in each subscription and apply Azure policies to each individually", "Create a management group, move all subscriptions into it, and assign Azure policies at the management group level", "Manually configure Azure Policy assignments on each of the 15 subscriptions separately"], answer: 2, explain: "Management groups let you assign Azure Policy once and have it apply to all current and future subscriptions beneath them — the most efficient approach." },
  { cat: "arch", topic: "a_core", q: "A company is planning to migrate its on-premises infrastructure to Azure. The IT manager needs to discover and assess 150 physical servers and 200 virtual machines running web applications, databases, and file servers — understanding migration readiness, estimating Azure costs, and identifying dependencies between servers. Which Azure service should they use?", options: ["Azure Migrate", "Azure Site Recovery", "Azure Monitor", "Azure Advisor"], answer: 0, explain: "Azure Migrate discovers and assesses servers and VMs for migration readiness, cost estimates, and dependency analysis." },
  { cat: "arch", topic: "a_network", q: "Your company stores sensitive customer data in an Azure Storage account. The security team requires that access to this storage account must never traverse the public internet and should only be accessible from resources within your Azure virtual network. Which Azure feature should you implement?", options: ["Enable the storage account firewall to allow only Azure services", "Configure a private endpoint for the Azure Storage account", "Configure a network security group (NSG) to restrict access to the storage account", "Enable a service endpoint for Azure Storage on the virtual network"], answer: 1, explain: "A private endpoint assigns the storage account a private IP within your VNet, so traffic stays on the Microsoft backbone and never traverses the public internet." },
  { cat: "govern", topic: "g_cost", q: "Your company is planning to migrate several on-premises workloads to Azure. The IT director asks you to estimate the monthly costs for running 5 virtual machines, 2 Azure SQL databases, and about 500 GB of blob storage, before deploying these resources. Which Azure tool should you use?", options: ["Azure Monitor", "Azure Advisor", "Microsoft Cost Management", "Azure Pricing Calculator"], answer: 3, explain: "The Azure Pricing Calculator creates detailed cost estimates for a planned configuration before any resources are deployed." },
  { cat: "govern", topic: "g_cost", q: "Your organization has deployed multiple Azure resources across different departments, including virtual machines, storage accounts, and Azure SQL databases. The finance department needs to generate monthly cost reports showing expenses for each department separately. What is the most effective way to use tags to accomplish this?", options: ["Apply a Department tag only to resource groups, since tags automatically inherit to all contained resources for billing", "Apply Department tags to resources and enable tag enforcement policies, which automatically generate cost reports grouped by department", "Apply a Department tag with values like \"Finance\", \"Marketing\", and \"IT\" to each resource, then use cost analysis to filter and group expenses by the Department tag", "Create separate Azure subscriptions for each department and apply Department tags at the subscription level"], answer: 2, explain: "Apply the Department tag to each resource, then filter/group by that tag in Cost analysis. (Resource tags do NOT automatically inherit from resource groups for billing.)" },

];
